mapper.select:
SELECT * FROM apt_complex
WHERE name = #{name} AND bjdong_code = #{bjdongCode}
LIMIT 1

SELECT * FROM apt_trade
WHERE complex_id = #{complexId}
ORDER BY deal_year DESC, deal_month DESC, deal_day DESC

SELECT t.* FROM apt_trade t
JOIN apt_complex c ON t.complex_id = c.id
WHERE c.bjdong_code = #{bjdongCode}
  AND t.deal_year = #{year}
  AND t.deal_month = #{month}
ORDER BY t.price DESC

SELECT EXISTS (
    SELECT 1 FROM apt_trade
    WHERE complex_id = #{complexId}
      AND deal_year = #{dealYear}
      AND deal_month = #{dealMonth}
      AND deal_day = #{dealDay}
      AND area = #{area}
      AND floor = #{floor}
)

SELECT * FROM apt_rent
WHERE complex_id = #{complexId}
ORDER BY deal_year DESC, deal_month DESC

SELECT EXISTS (
    SELECT 1 FROM apt_rent
    WHERE complex_id = #{complexId}
      AND deal_year = #{dealYear}
      AND deal_month = #{dealMonth}
      AND area = #{area}
      AND floor = #{floor}
      AND deposit = #{deposit}
)

SELECT * FROM ( SELECT c.id, c.name, c.road_addr, c.sigungu, c.dong, c.lat, c.lng, c.total_household, c.build_year, CAST(AVG(t.price) AS INTEGER) AS avg_trade_price, CAST(AVG(CASE WHEN r.rent_type = '전세' THEN r.deposit END) AS INTEGER) AS avg_deposit_price,
/* * Haversine 거리 계산 (단위: km) * * 6371: 지구 평균 반지름(km) * radians(): 도(degree) → 라디안 변환 (삼각함수는 라디안 단위 사용) * #{lat}, #{lng}: 사용자가 클릭한 기준 좌표 * c.lat, c.lng: DB에 저장된 각 단지의 좌표 * * LEAST(1.0, ...): 부동소수점 연산 오차로 acos(x)의 x가 1.0000001처럼 * 1을 초과하면 acos가 NaN을 반환하므로 상한을 1.0으로 고정 */ ( 6371 * acos( LEAST(1.0, cos(radians(#{lat})) * cos(radians(c.lat)) * cos(radians(c.lng) - radians(#{lng})) + sin(radians(#{lat})) * sin(radians(c.lat)) ) ) ) AS distance_km
FROM apt_complex c
/* 최근 1년 매매 실거래 JOIN (없으면 avg_trade_price = null) */ LEFT JOIN apt_trade t ON c.id = t.complex_id AND t.deal_year >= EXTRACT(YEAR FROM CURRENT_DATE)::int - 1
/* 최근 1년 전세 실거래 JOIN (없으면 avg_deposit_price = null) */ LEFT JOIN apt_rent r ON c.id = r.complex_id AND r.rent_type = '전세' AND r.deal_year >= EXTRACT(YEAR FROM CURRENT_DATE)::int - 1
/* 좌표 없는 단지는 거리 계산 불가이므로 제외 */ WHERE c.lat IS NOT NULL AND c.lng IS NOT NULL
GROUP BY c.id, c.name, c.road_addr, c.sigungu, c.dong, c.lat, c.lng, c.total_household, c.build_year ) sub
/* 서브쿼리 밖에서 distance_km alias로 반경 필터링 */ WHERE sub.distance_km <= #{radiusKm} ORDER BY sub.distance_km ASC LIMIT 30

SELECT c.id, c.name, c.road_addr, c.sigungu, c.dong, c.lat, c.lng, CAST(AVG(t.price) AS INTEGER) AS avg_trade_price, CAST(AVG(CASE WHEN r.rent_type = '전세' THEN r.deposit END) AS INTEGER) AS avg_deposit_price FROM apt_complex c LEFT JOIN apt_trade t ON c.id = t.complex_id AND t.deal_year >= EXTRACT(YEAR FROM CURRENT_DATE)::int - 1 LEFT JOIN apt_rent r ON c.id = r.complex_id AND r.deal_year >= EXTRACT(YEAR FROM CURRENT_DATE)::int - 1 WHERE c.sigungu = #{sigungu}
AND c.dong = #{dong}
GROUP BY c.id, c.name, c.road_addr, c.sigungu, c.dong, c.lat, c.lng ORDER BY avg_trade_price ASC NULLS LAST LIMIT 100
